#include <iostream>
using namespace std;

class Rectangle {
private:
 int length;
 int breadth;

public:
 // Constructor
 Rectangle(int l = 0, int b = 0) {
 length = l;
 breadth = b;
 }

 // Member functions
 void setDimensions(int l, int b) {
 length = l;
 breadth = b;
 }

 int area() {
 return length * breadth;
 }

 int perimeter() {
 return 2 * (length + breadth);
 }

 // Destructor
 ~Rectangle() {
 cout << "Object destroyed" << endl;
 }
};

int main() {
 Rectangle r1(10, 5);
 Rectangle r2;

 cout << "Area of r1: " << r1.area() << endl;
 cout << "Perimeter of r1: " << r1.perimeter() << endl;

 r2.setDimensions(20, 10);
 cout << "Area of r2: " << r2.area() << endl;

 return 0;
}

#include <iostream>
using namespace std;

class Box {
private:
 int width;
 int height;

public:
 // Using this pointer to differentiate parameter from member
 void setDimensions(int width, int height) {
 this->width = width;
 this->height = height;
 }

 // Using this to return current object
 Box* getAddress() {
 return this;
 }

 void display() {
 cout << "Width: " << width << endl;
 cout << "Height: " << height << endl;
 }
};

int main() {
 Box b1;
 b1.setDimensions(10, 20);
 b1.display();

 cout << "Address of object: " << b1.getAddress() << endl;

 return 0;
}

#include <iostream>
using namespace std;

class Counter {
private:
 int count; // Instance variable (different for each object)
 static int objCount; // Static variable (shared by all objects)

public:
 Counter() {
 count = 0;
 objCount++;
 }

 void increment() {
 count++;
 objCount++;
 }

 void display() {
 cout << "Count: " << count << endl;
 cout << "Object Count: " << objCount << endl;
 }

 static int getObjCount() {
 return objCount;
 }
};

// Initialize static member outside class
int Counter::objCount = 0;

int main() {
 Counter c1, c2, c3;

 c1.increment();
 c2.increment();

 c1.display();
 c2.display();

 cout << "Total objects created: " << Counter::getObjCount() << endl;

 return 0;
}

#include <iostream>
using namespace std;

class Distance {
private:
 int meters;

public:
 Distance(int m = 0) {
 meters = m;
 }

 // Declaration of friend function
 friend void displayDistance(Distance d);

 // Friend class example
 friend class Printer;
};

// Friend function definition - not a member function
void displayDistance(Distance d) {
 // Can access private member despite not being a member
 cout << "Distance: " << d.meters << " meters" << endl;
}

class Printer {
public:
 void print(Distance d) {
 cout << "Printing from friend class: " << d.meters << endl;
 }
};

int main() {
 Distance d1(100);
 displayDistance(d1); // Calling friend function

 Printer p;
 p.print(d1); // Using friend class

 return 0;
}
